const PointForm = () => {
  
  return (
	<div className="box">
      <h3>Параметры точки</h3>

      <div>
        <label>X:</label>
        {-3,-2,-1,0,1,2,3,4,5}
      </div>

      <div>
        <label>Y:</label>
        <input type="text" placeholder="-3 ... 3" />
      </div>

      <div>
        <label>R:</label>
        {-3,-2,-1,0,1,2,3,4,5}
      </div>

      <button>Проверить</button>
    </div>
  );
};

export default PointForm;
